#include <stdio.h>

int main() {
  int numbers[4] = {10, 20, 30, 40};
  int *ptr = numbers;
  printf("First element: %d\n", *ptr);
  ptr = ptr + 1;
  printf("Second element: %d\n", *ptr);
  ptr = ptr + 2;
  printf("Fourth element: %d\n", *ptr);
  return 0;
}
// Output:
// First element: 10
// Second element: 20
// Fourth element: 40

#include <stdio.h>

int main() {
  int numbers[5] = {100, 200, 300, 400, 500};
  int *ptr = numbers;
  for (int i = 0; i < 5; i++) {
    printf("Element %d: %d (Address: %p)\n", i, *(ptr + i), (void *)(ptr + i));
  }
  return 0;
}
// Output:
// Element 0: 100 (Address: 0x...)
// Element 1: 200 (Address: 0x... + 4)
// Element 2: 300 (Address: 0x... + 8)
// Element 3: 400 (Address: 0x... + 12)
// Element 4: 500 (Address: 0x... + 16)

#include <stdio.h>

int main() {
  int numbers[5] = {1, 2, 3, 4, 5};
  int *ptr1 = &numbers[1];
  int *ptr2 = &numbers[4];
  int distance = ptr2 - ptr1;
  printf("Distance between ptr2 and ptr1: %d elements\n", distance);
  return 0;
}
// Output:
// Distance between ptr2 and ptr1: 3 elements

#include <stdio.h>

int main() {
  char text[] = "Hello";
  char *ptr = text;
  for (int i = 0; i < 5; i++) {
    printf("Character %d: %c (Address: %p)\n", i, *(ptr + i), (void *)(ptr + i));
  }
  return 0;
}
// Output:
// Character 0: H (Address: 0x...)
// Character 1: e (Address: 0x... + 1)
// Character 2: l (Address: 0x... + 2)
// Character 3: l (Address: 0x... + 3)
// Character 4: o (Address: 0x... + 4)

#include <stdio.h>

int main() {
  int numbers[3] = {1, 2, 3};
  int *ptr = numbers;
  printf("Invalid element: %d\n", *(ptr + 5));
  return 0;
}
// Output: (Gözlənilməz nəticə, çünki ptr + 5 massiv sərhədlərindən kənardır)

